import org.owasp.encoder.Encode;

import java.util.Scanner;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and escape user input before embedding it in the HTML response
        String sanitizedUserInput = Encode.forHtml(userInput);

        String htmlResponse = "<h1>Welcome, " + sanitizedUserInput + "!</h1>";

        System.out.println(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
